'use client';

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { 
  Menu, X, Plus, MessageSquare, Search, Settings, LogOut,
  ChevronRight, Calendar, Clock, Hash
} from 'lucide-react';
import { Button } from '@/components/ui/Button';
import { Input } from '@/components/ui/Input';
import { Card } from '@/components/ui/Card';
import { ChatSession } from '@/lib/types';
import { chatService } from '@/services/chat.service';
import { cn } from '@/lib/utils/cn';

interface SidebarProps {
  currentSessionId?: string;
  onSessionSelect: (sessionId: string) => void;
  onNewChat: () => void;
}

export function Sidebar({ currentSessionId, onSessionSelect, onNewChat }: SidebarProps) {
  const [isOpen, setIsOpen] = useState(true);
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    loadSessions();
  }, []);

  const loadSessions = async () => {
    try {
      setIsLoading(true);
      const data = await chatService.getSessions();
      setSessions(data);
    } catch (error) {
      console.error('Failed to load sessions:', error);
    } finally {
      setIsLoading(false);
    }
  };

  const handleDeleteSession = async (sessionId: string, e: React.MouseEvent) => {
    e.stopPropagation();
    
    try {
      await chatService.deleteSession(sessionId);
      setSessions((prev) => prev.filter((s) => s.id !== sessionId));
      
      if (currentSessionId === sessionId) {
        onNewChat();
      }
    } catch (error) {
      console.error('Failed to delete session:', error);
    }
  };

  const filteredSessions = sessions.filter((session) =>
    session.title.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const groupSessionsByDate = (sessions: ChatSession[]) => {
    const groups: Record<string, ChatSession[]> = {};
    const today = new Date();
    const yesterday = new Date(today);
    yesterday.setDate(yesterday.getDate() - 1);
    const lastWeek = new Date(today);
    lastWeek.setDate(lastWeek.getDate() - 7);

    sessions.forEach((session) => {
      const sessionDate = new Date(session.createdAt);
      let group = 'Older';

      if (sessionDate.toDateString() === today.toDateString()) {
        group = 'Today';
      } else if (sessionDate.toDateString() === yesterday.toDateString()) {
        group = 'Yesterday';
      } else if (sessionDate > lastWeek) {
        group = 'Last 7 days';
      }

      if (!groups[group]) {
        groups[group] = [];
      }
      groups[group].push(session);
    });

    return groups;
  };

  const sessionGroups = groupSessionsByDate(filteredSessions);

  return (
    <>
      {/* Mobile Toggle */}
      <Button
        variant="ghost"
        size="icon"
        className="fixed left-4 top-4 z-50 md:hidden"
        onClick={() => setIsOpen(!isOpen)}
      >
        {isOpen ? <X className="h-5 w-5" /> : <Menu className="h-5 w-5" />}
      </Button>

      {/* Sidebar */}
      <AnimatePresence>
        {isOpen && (
          <motion.aside
            initial={{ x: -300 }}
            animate={{ x: 0 }}
            exit={{ x: -300 }}
            transition={{ type: 'spring', stiffness: 300, damping: 30 }}
            className={cn(
              'fixed left-0 top-0 z-40 h-full w-80 border-r border-neutral-200 bg-white dark:border-neutral-800 dark:bg-neutral-900',
              'md:relative md:z-0'
            )}
          >
            <div className="flex h-full flex-col">
              {/* Header */}
              <div className="border-b border-neutral-200 p-4 dark:border-neutral-800">
                <div className="mb-4 flex items-center justify-between">
                  <h1 className="text-xl font-bold text-gradient">Legal AI</h1>
                  <Button
                    variant="ghost"
                    size="icon"
                    className="md:hidden"
                    onClick={() => setIsOpen(false)}
                  >
                    <X className="h-5 w-5" />
                  </Button>
                </div>
                
                <Button
                  onClick={onNewChat}
                  className="w-full"
                  size="sm"
                >
                  <Plus className="mr-2 h-4 w-4" />
                  New Chat
                </Button>
              </div>

              {/* Search */}
              <div className="border-b border-neutral-200 p-4 dark:border-neutral-800">
                <Input
                  type="search"
                  placeholder="Search conversations..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  icon={<Search className="h-4 w-4" />}
                />
              </div>

              {/* Sessions List */}
              <div className="flex-1 overflow-y-auto p-4">
                {isLoading ? (
                  <div className="space-y-3">
                    {[...Array(5)].map((_, i) => (
                      <div key={i} className="h-16 animate-pulse rounded-lg bg-neutral-100 dark:bg-neutral-800" />
                    ))}
                  </div>
                ) : filteredSessions.length === 0 ? (
                  <div className="text-center text-sm text-neutral-500 dark:text-neutral-400">
                    {searchQuery ? 'No matching conversations' : 'No conversations yet'}
                  </div>
                ) : (
                  <div className="space-y-4">
                    {Object.entries(sessionGroups).map(([group, groupSessions]) => (
                      <div key={group}>
                        <h3 className="mb-2 text-xs font-semibold uppercase text-neutral-500 dark:text-neutral-400">
                          {group}
                        </h3>
                        <div className="space-y-2">
                          {groupSessions.map((session) => (
                            <Card
                              key={session.id}
                              variant={currentSessionId === session.id ? 'default' : 'bordered'}
                              className={cn(
                                'cursor-pointer p-3 transition-all hover:shadow-sm',
                                currentSessionId === session.id && 'border-secondary'
                              )}
                              onClick={() => onSessionSelect(session.id)}
                            >
                              <div className="flex items-start justify-between">
                                <div className="flex-1 overflow-hidden">
                                  <h4 className="truncate font-medium">{session.title}</h4>
                                  <div className="mt-1 flex items-center gap-3 text-xs text-neutral-500 dark:text-neutral-400">
                                    <span className="flex items-center gap-1">
                                      <MessageSquare className="h-3 w-3" />
                                      {session.messages.length}
                                    </span>
                                    <span className="flex items-center gap-1">
                                      <Clock className="h-3 w-3" />
                                      {new Date(session.updatedAt).toLocaleTimeString('en-IN', {
                                        hour: '2-digit',
                                        minute: '2-digit',
                                      })}
                                    </span>
                                  </div>
                                </div>
                                <Button
                                  variant="ghost"
                                  size="icon"
                                  className="h-8 w-8 opacity-0 transition-opacity hover:opacity-100"
                                  onClick={(e) => handleDeleteSession(session.id, e)}
                                >
                                  <X className="h-4 w-4" />
                                </Button>
                              </div>
                            </Card>
                          ))}
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </div>

              {/* Footer */}
              <div className="border-t border-neutral-200 p-4 dark:border-neutral-800">
                <div className="space-y-2">
                  <Button variant="ghost" size="sm" className="w-full justify-start">
                    <Settings className="mr-2 h-4 w-4" />
                    Settings
                  </Button>
                  <Button variant="ghost" size="sm" className="w-full justify-start text-red-600 hover:text-red-700 dark:text-red-400">
                    <LogOut className="mr-2 h-4 w-4" />
                    Sign Out
                  </Button>
                </div>
              </div>
            </div>
          </motion.aside>
        )}
      </AnimatePresence>

      {/* Backdrop for mobile */}
      <AnimatePresence>
        {isOpen && (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            className="fixed inset-0 z-30 bg-black/50 md:hidden"
            onClick={() => setIsOpen(false)}
          />
        )}
      </AnimatePresence>
    </>
  );
} 