'use client';

import React, { useState, useRef, KeyboardEvent } from 'react';
import { Send, Paperclip, AlertCircle } from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { Button } from '@/components/ui/Button';
import { cn } from '@/lib/utils/cn';

interface ChatInputProps {
  onSendMessage: (message: string) => void;
  isLoading?: boolean;
  placeholder?: string;
  suggestions?: string[];
}

export function ChatInput({
  onSendMessage,
  isLoading = false,
  placeholder = 'Ask about Indian law, cases, or legal procedures...',
  suggestions = [],
}: ChatInputProps) {
  const [message, setMessage] = useState('');
  const [isFocused, setIsFocused] = useState(false);
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  const handleSend = () => {
    if (message.trim() && !isLoading) {
      onSendMessage(message.trim());
      setMessage('');
      
      // Reset textarea height
      if (textareaRef.current) {
        textareaRef.current.style.height = 'auto';
      }
    }
  };

  const handleKeyDown = (e: KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const handleTextareaChange = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
    setMessage(e.target.value);
    
    // Auto-resize textarea
    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto';
      textareaRef.current.style.height = `${textareaRef.current.scrollHeight}px`;
    }
  };

  const handleSuggestionClick = (suggestion: string) => {
    setMessage(suggestion);
    textareaRef.current?.focus();
  };

  return (
    <div className="relative">
      {/* Suggestions */}
      <AnimatePresence>
        {suggestions.length > 0 && !message && isFocused && (
          <motion.div
            initial={{ opacity: 0, y: 10 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: 10 }}
            className="absolute bottom-full left-0 mb-2 flex w-full flex-wrap gap-2 px-4"
          >
            <span className="text-xs text-neutral-500 dark:text-neutral-400">
              Try asking:
            </span>
            {suggestions.map((suggestion, index) => (
              <button
                key={index}
                onClick={() => handleSuggestionClick(suggestion)}
                className="rounded-full bg-neutral-100 px-3 py-1 text-xs font-medium text-neutral-700 transition-colors hover:bg-neutral-200 dark:bg-neutral-800 dark:text-neutral-300 dark:hover:bg-neutral-700"
              >
                {suggestion}
              </button>
            ))}
          </motion.div>
        )}
      </AnimatePresence>

      {/* Input Area */}
      <div
        className={cn(
          'flex items-end gap-2 rounded-lg border bg-white p-2 transition-all dark:bg-neutral-900',
          isFocused
            ? 'border-secondary ring-2 ring-secondary/20 shadow-lg'
            : 'border-neutral-300 dark:border-neutral-700'
        )}
      >
        <button
          type="button"
          className="mb-1 rounded-md p-2 text-neutral-500 transition-colors hover:bg-neutral-100 hover:text-neutral-700 dark:text-neutral-400 dark:hover:bg-neutral-800 dark:hover:text-neutral-200"
          aria-label="Attach file"
        >
          <Paperclip className="h-5 w-5" />
        </button>

        <textarea
          ref={textareaRef}
          value={message}
          onChange={handleTextareaChange}
          onKeyDown={handleKeyDown}
          onFocus={() => setIsFocused(true)}
          onBlur={() => setIsFocused(false)}
          placeholder={placeholder}
          disabled={isLoading}
          className="min-h-[44px] max-h-[200px] flex-1 resize-none bg-transparent px-2 py-3 text-sm outline-none placeholder:text-neutral-500 disabled:opacity-50 dark:placeholder:text-neutral-400"
          rows={1}
        />

        <Button
          onClick={handleSend}
          disabled={!message.trim() || isLoading}
          size="icon"
          className="mb-1"
          aria-label="Send message"
        >
          <Send className="h-4 w-4" />
        </Button>
      </div>

      {/* Character count warning */}
      {message.length > 4000 && (
        <div className="mt-2 flex items-center gap-1 px-4 text-xs text-amber-600 dark:text-amber-400">
          <AlertCircle className="h-3 w-3" />
          <span>Message is too long ({message.length}/4000 characters)</span>
        </div>
      )}
    </div>
  );
}