import React from 'react';
import { cn } from '@/lib/utils/cn';

export interface InputProps
  extends React.InputHTMLAttributes<HTMLInputElement> {
  error?: boolean;
  icon?: React.ReactNode;
}

const Input = React.forwardRef<HTMLInputElement, InputProps>(
  ({ className, type, error, icon, ...props }, ref) => {
    return (
      <div className="relative">
        {icon && (
          <div className="absolute left-3 top-1/2 -translate-y-1/2 text-neutral-500 dark:text-neutral-400">
            {icon}
          </div>
        )}
        <input
          type={type}
          className={cn(
            'flex h-10 w-full rounded-md border bg-white px-3 py-2 text-sm transition-all',
            'placeholder:text-neutral-500 dark:placeholder:text-neutral-400',
            'focus:outline-none focus:ring-2 focus:ring-offset-2',
            'disabled:cursor-not-allowed disabled:opacity-50',
            'dark:bg-neutral-900',
            icon && 'pl-10',
            error
              ? 'border-red-500 focus:ring-red-500'
              : 'border-neutral-300 focus:ring-secondary-500 dark:border-neutral-700',
            className
          )}
          ref={ref}
          aria-invalid={error}
          {...props}
        />
      </div>
    );
  }
);

Input.displayName = 'Input';

export { Input }; 